use std::io::stdin;

fn main() {
    let mut args = String::new();
    stdin().read_line(&mut args).unwrap();
    let mut amount: u32 = 0;
    for digit in args.trim_end().chars() {
        if digit == '4' || digit == '7' {
            amount += 1;
        }
    }
    if amount.to_string() == "4" || amount.to_string() == "7" {
        println!("YES");
    } else {
        println!("NO");
    }
}
